select a.article_id, a.title, a.author_names, i.year, i.period, a.page_start, a.page_end, ifnull(a.cited_count, 0) as cited_count, ifnull(a.self_cited_count, 0) as self_cited_count, ifnull( a.other_cited_count, greatest(ifnull(a.cited_count, 0) - ifnull(a.self_cited_count, 0), 0) ) as other_cited_count from publisher_article a left join publisher_issue i on i.issue_id = a.issue_id
AND a.title like concat('%', #{title}, '%')
AND a.author_names like concat('%', #{authorNames}, '%')
AND i.year = #{year}
AND i.period = #{period}
AND i.year >= #{params.beginYear}
AND i.year <= #{params.endYear}
order by ifnull(a.cited_count, 0) desc, i.year desc, i.period desc, a.article_id desc
